#!/usr/bin/env node
/**
 * Verb Allowlist Generator — Feature A · A2b
 *
 * Reads `protocol-catalog.json` and emits `src/generated/verbAllowlist.ts`
 * with one `Set<string>` export per provider (`KANBAN_VERBS`, `PLANNING_VERBS`,
 * `DESIGN_VERBS`, `TASKVIEWER_VERBS`, `SETUP_VERBS`). Generated, checked in,
 * and regenerated by the `catalog:generate` npm script so the allowlist can
 * never drift from the catalog — the generic dispatcher's allowlist ≡ catalog
 * by construction.
 *
 * Source of truth per provider is `providers.<Name>.verbs[]` (not `armCount`).
 *
 * Usage: node scripts/generate-verb-allowlist.js [--write]
 *   --write  overwrite the checked-in src/generated/verbAllowlist.ts (CI drift
 *            check runs without --write and exits non-zero on drift).
 */

'use strict';

const fs = require('fs');
const path = require('path');

const REPO_ROOT = path.resolve(__dirname, '..');
const CATALOG_PATH = path.join(REPO_ROOT, 'protocol-catalog.json');
const OUTPUT_PATH = path.join(REPO_ROOT, 'src', 'generated', 'verbAllowlist.ts');

// Provider name → exported Set name. Order matches the catalog's PROVIDERS.
const PROVIDER_SETS = [
    { name: 'Kanban', set: 'KANBAN_VERBS' },
    { name: 'Planning', set: 'PLANNING_VERBS' },
    { name: 'Design', set: 'DESIGN_VERBS' },
    { name: 'TaskViewer', set: 'TASKVIEWER_VERBS' },
    { name: 'Setup', set: 'SETUP_VERBS' },
];

function buildAllowlist() {
    if (!fs.existsSync(CATALOG_PATH)) {
        console.error(`[allowlist] protocol-catalog.json not found. Run \`npm run catalog:generate\` first.`);
        process.exit(1);
    }
    const catalog = JSON.parse(fs.readFileSync(CATALOG_PATH, 'utf8'));

    const lines = [];
    lines.push('// AUTO-GENERATED — do not edit; run `npm run catalog:generate`.');
    lines.push('// Source: protocol-catalog.json providers.<Name>.verbs[]');
    lines.push('// Any change to the verb surface regenerates this file automatically.');
    lines.push('');
    lines.push('/* eslint-disable */');
    lines.push('');

    for (const p of PROVIDER_SETS) {
        const verbs = (catalog.providers[p.name] && catalog.providers[p.name].verbs) || [];
        const sorted = Array.from(verbs).sort();
        const setLiteral = sorted.map(v => `'${v.replace(/'/g, "\\'")}'`).join(', ');
        lines.push(`export const ${p.set}: Set<string> = new Set([${setLiteral}]);`);
        lines.push('');
    }

    return lines.join('\n');
}

function main() {
    const args = process.argv.slice(2);
    const write = args.includes('--write');
    const output = buildAllowlist();

    if (write) {
        fs.mkdirSync(path.dirname(OUTPUT_PATH), { recursive: true });
        fs.writeFileSync(OUTPUT_PATH, output);
        console.error(`[allowlist] wrote ${path.relative(REPO_ROOT, OUTPUT_PATH)}`);
        return;
    }

    // Drift check: compare regenerated vs checked-in.
    let existing = null;
    try { existing = fs.readFileSync(OUTPUT_PATH, 'utf8'); }
    catch { /* not generated yet */ }

    if (!existing) {
        console.error(`[allowlist] ${path.relative(REPO_ROOT, OUTPUT_PATH)} not found — run \`npm run catalog:generate\` first`);
        process.exit(1);
    }

    if (existing.trim() !== output.trim()) {
        console.error(`[allowlist] DRIFT — ${path.relative(REPO_ROOT, OUTPUT_PATH)} does not match protocol-catalog.json. Run \`npm run catalog:generate\` to regenerate.`);
        process.exit(1);
    }

    console.log(`[allowlist] OK — ${path.relative(REPO_ROOT, OUTPUT_PATH)} matches protocol-catalog.json`);
}

main();
